// Montar relatório executivo
const fases = $('Stats — Leads por Fase').all().map(i => i.json);
const mensagens = $('Stats — Mensagens Hoje').all().map(i => i.json);
const pagamentos = $('Stats — Pagamentos Hoje').first().json;
const custos = $('Stats — Custos Hoje').first().json;

const totalLeads = fases.reduce((s, f) => s + Number(f.total), 0);
const totalDivida = fases.reduce((s, f) => s + Number(f.valor_total || 0), 0);
const totalMensagens = mensagens.reduce((s, m) => s + Number(m.enviados), 0);
const hoje = new Date().toLocaleDateString('pt-BR');

const linhasFases = fases.map(f => {
  const desconto = { pre:0, mes1:0, mes2:0, mes3:5, mes4:15, mes5:20, pos:0 }[f.fase_cobranca] || 0;
  return `  • ${f.fase_cobranca.padEnd(5)}: ${f.total} leads | R$ ${Number(f.valor_total || 0).toLocaleString('pt-BR')} | ~${Math.round(f.media_dias || 0)}d atraso${desconto > 0 ? ` (${desconto}% desc. ativo)` : ''}`;
}).join('\n');

const relatorio = `RELATORIO DIARIO — PLANO MAIS INADIMPLENCIA
${hoje} | Gerado pelo WF6 Diagnostico

== CARTEIRA ATUAL ==
Total de inadimplentes: ${totalLeads} leads
Valor total em aberto: R$ ${totalDivida.toLocaleString('pt-BR')}

Distribuicao por fase:
${linhasFases}

== ATIVIDADE DE HOJE ==
Mensagens disparadas: ${totalMensagens}
Pagamentos recebidos: ${pagamentos.pagamentos_hoje || 0}
Valor recuperado: R$ ${Number(pagamentos.valor_recuperado_hoje || 0).toLocaleString('pt-BR')}
  via PIX: ${pagamentos.via_pix || 0}
  via Boleto: ${pagamentos.via_boleto || 0}
  via Cartao: ${pagamentos.via_cartao || 0}

== CUSTOS OPERACIONAIS ==
Custo total hoje: R$ ${Number(custos.custo_dia || 0).toFixed(4)}

== ALERTAS ==
${fases.filter(f => f.fase_cobranca === 'mes5' && f.total > 0).length > 0 ? 'ATENCAO: Leads em mes5 — contato urgente necessario!' : 'Sem alertas criticos'}

Proximo scheduler: amanha 08h00`;

return [{ json: { relatorio, dados: { fases, pagamentos, totalLeads, totalDivida } } }];
